type SplitResult {
    lo: Int;
    hi: Int;
}

@pure
fn split(n: Int) -> SplitResult {
    if n <= 0 {
        ret new SplitResult { lo: 0, hi: 0 };
    }
    let prev: SplitResult = split(n - 1);
    ret new SplitResult { lo: prev.lo + 1, hi: prev.hi + 2 };
}

fn main() -> Void {
    let parts: SplitResult = split(3);
    fx { println(parts.lo, " ", parts.hi); }
    ret;
}
